const all = $input.all().map(i => i.json).filter(x => x && Object.keys(x).length);
if (!all.length) {
  return [{json:{success:false,respuesta_agente:'No encontré pedidos modificables vigentes para tu número.', pedidos:[]}}];
}
if (all.length === 1) {
  const p = all[0];
  return [{
    json: {
      success: true,
      seleccion_requerida: false,
      pedido_id: p.pedido_id,
      pedido_codigo: p.pedido_codigo,
      respuesta_agente: `Puedo modificar el pedido ${p.pedido_codigo}. ¿Qué cambio quieres hacer?`,
      pedido: p
    }
  }];
}
const texto = all.map(p => `${p.pedido_codigo} (${p.tipo_despacho || 'sin despacho'}, total €${Number(p.total || 0).toFixed(2).replace('.',',')})`).join(', ');
return [{
  json: {
    success: true,
    seleccion_requerida: true,
    pedidos: all,
    respuesta_agente: `Tienes varios pedidos aún modificables: ${texto}. ¿Cuál quieres modificar?`
  }
}];

const p = $json || {};
const trigger = $('When Executed by Another Workflow').first().json || {};
const accion = String(trigger.accion || 'resolver').toLowerCase().trim();

function money(v) {
  return '€' + Number(v || 0).toFixed(2).replace('.', ',');
}

let items = [];
try {
  items = Array.isArray(p.items) ? p.items : JSON.parse(p.items || '[]');
} catch {
  items = [];
}
const itemsTexto = items.length ? items.map(i => `${Number(i.cantidad || 1)}x ${i.nombre}`).join(', ') : 'sin detalle disponible';
const tiempo = p.tiempo_estimado ? ` Tiempo estimado: ${p.tiempo_estimado}.` : '';
const despacho = p.tipo_despacho === 'delivery'
  ? `Delivery${p.direccion ? ` a ${p.direccion}` : ''}.`
  : p.tipo_despacho === 'retiro'
    ? 'Retiro en el local.'
    : 'Despacho aún no definido.';
const pago = p.metodo_pago ? ` Pago: ${p.metodo_pago}.` : '';

if (!p.pedido_id) {
  return [{json:{success:false,respuesta_agente:'No pude identificar ese pedido. Envíame el código exacto, por ejemplo 260418-1006.'}}];
}

if (accion === 'consultar') {
  return [{
    json: {
      success: true,
      seleccion_requerida: false,
      pedido_id: p.pedido_id,
      pedido_codigo: p.pedido_codigo,
      es_modificable: Boolean(p.es_modificable),
      respuesta_agente: `El pedido ${p.pedido_codigo} lleva ${itemsTexto}. Estado: ${p.estado}. ${despacho} Total: ${money(p.total || 0)}.${tiempo}${pago}`.replace(/\s+/g, ' ').trim(),
      pedido: p
    }
  }];
}

if (!p.es_modificable) {
  return [{
    json: {
      success: false,
      derivar_humano: true,
      motivo_derivacion: 'ventana_modificacion_expirada',
      seleccion_requerida: false,
      pedido_id: p.pedido_id,
      pedido_codigo: p.pedido_codigo,
      es_modificable: false,
      respuesta_agente: `El pedido ${p.pedido_codigo} ya no puede modificarse (ventana de cambios expirada). Derivar a operador humano.`,
      pedido: p
    }
  }];
}

return [{
  json: {
    success: true,
    seleccion_requerida: false,
    pedido_id: p.pedido_id,
    pedido_codigo: p.pedido_codigo,
    es_modificable: true,
    respuesta_agente: `Perfecto, trabajaré sobre el pedido ${p.pedido_codigo}. ¿Qué cambio quieres hacer?`,
    pedido: p
  }
}];
